static inline void softmax_transform(float* w, const uint n)
{
    float d = 0;
    for(uint i = 0; i < n; i++)
        d += exp(w[i]);

    for(uint i = 0; i < n; i++)
        w[i] = exp(w[i]) / d;
}
float crossEntropy(const float predicted, const float expected) //log loss
{
    if(expected == 1)
        return -log(predicted);
    else
        return -log(1 - predicted);
}

