// I would like to eventually compact the lookup code into a single swiss-army like function, this function is the workings towards that.
static inline float table_lerp(const float sa, const float ia, const float sb, const float ib, const float i)
{
    return sa + (( (i - ia) / (ib - ia) ) * (sb - sa));
}
static inline float table_derivative(const float* ts, const float* ti, const uint table_size, const float fi, const float fn)
{
    const uint i = (uint)(table_size * fn);
    if(i > table_size){return ts[table_size];}
    return table_lerp(ts[i], ti[i], ts[i+1], ti[i+1], fi);
}
// don't laugh at me please, i am serious. :'( you have better way ? you email me ^ in header
static inline float find_derivative(const float* ts, const float* ti, const uint table_size, const float fi, const float fn)
{
    for(uint i = 0; i < table_size; i++)
    {
        if(fi >= ti[i] && fi < ti[i+1])
            return table_lerp(ts[i], ti[i], ts[i+1], ti[i+1], fi);
        else if(fi <= ti[i] && fi > ti[i+1])
            return table_lerp(ts[i], ti[i], ts[i+1], ti[i+1], fi);
    }
    return table_derivative(ts, ti, table_size, fi, fn);
}

/**********************************************/

static inline float softplus(const float x) //derivative is sigmoid()
{
    return log(1 + exp(x));
}

static inline float atanDerivative(const float x) //atan()
{
    return 1 / (1 + (x*x));
}

static inline float tanhDerivative(const float x) //tanh()
{
    return 1 - (x*x);
}

/**********************************************/

static inline float elu(const network* net, const float x)
{
    if(x <= 0){return -net->elualpha * (exp(x) - 1);}
    return x;
}

static inline float eluDerivative(const network* net, const float x)
{
    if(x > 0){return 1;}
    return net->elualpha * exp(x);
}

/**********************************************/

static inline float gelu(const float x)
{
    return 0.5 * x * (1 + tanh( 0.7978845608 * ( x + 0.044715 * (x*x*x) ) ));
}

