static inline float sqnl(const float x)
{
    if(x > 2.0){return 1;}
    else if(x < -2.0){return -1.0;}
    else if(x <= 2.0 && x >= 0){return (x-(x*x))*0.25;}
    return (x+(x*x))*0.25;
}

